            console.error('Failed to copy:', err);
          });
        }
      },
    },
    {
      type: 'hover-activate',
      state: 'hover',
      enable: (event) => event.targetType === 'node',
    },
  ],
  plugins: [
    {
      type: 'tooltip',
      getContent: (event, items) => {
        const item = items[0];
        if (!item) return '';

        const { data } = item;
        return `
          <div style="padding: 12px; min-width: 200px; background: #fff; border-radius: 4px; box-shadow: 0 2px 8px rgba(0,0,0,0.15);">
            <div style="font-weight: bold; margin-bottom: 8px; color: #1890ff; font-size: 16px;">Node Information</div>
            <div style="margin-bottom: 4px;"><strong>ID:</strong> ${item.id}</div>
            <div style="margin-bottom: 4px;"><strong>Label:</strong> ${data.label}</div>
            ${data.description ? `<div style="color: #666; font-size: 12px; margin-top: 8px;">${data.description}</div>` : ''}
            <div style="margin-top: 8px; padding-top: 8px; border-top: 1px solid #e8e8e8; color: #52c41a; font-size: 12px;">
              ✓ Click node to copy label text
            </div>
          </div>
        `;
      },
      offset: [10, 10],
    },
    'grid-line',
  ],
  background: {
    color: '#f8fafc',
  },
});

graph.render();

// Add visual feedback for copy action
graph.on('node:click', (e) => {
  const nodeId = e.target.id;
  const originalFill = graph.getNodeData(nodeId).style?.fill;

  // Flash effect to indicate copy
  graph.updateNodeData([
    {
      id: nodeId,
      style: {
        fill: '#52c41a',
      },
    },
  ]);
  graph.draw();

  setTimeout(() => {
    graph.updateNodeData([
      {
        id: nodeId,
        style: {
          fill: originalFill || '#e6f7ff',
        },
      },
    ]);
    graph.draw();
  }, 200);
});

