import { Graph, treeToGraphData } from '@antv/g6';

const getNodeSide = (graph, datum) => {
  const parentData = graph.getParentData(datum.id, 'tree');
  if (!parentData) return 'center';
  return datum.style.x > parentData.style.x ? 'right' : 'left';
};

const data = {
   "id": "Modeling Methods",
   "children": [
     {
       "id": "Classification",
       "children": [
         {
           "id": "Logistic regression"
         },
         {
           "id": "Linear discriminant analysis"
         },
         {
           "id": "Rules"
         },
         {
           "id": "Decision trees"
         },
         {
           "id": "Naive Bayes"
         },
         {
           "id": "K nearest neighbor"
         },
         {
           "id": "Probabilistic neural network"
         },
         {
           "id": "Support vector machine"
         }
       ]
     },
     {
       "id": "Consensus",
       "children": [
         {
           "id": "Models diversity",
           "children": [
             {
               "id": "Different initializations"
             },
             {
               "id": "Different parameter choices"
             },
             {
               "id": "Different architectures"
             },
             {
               "id": "Different modeling methods"
             },
             {
               "id": "Different training sets"
             },
             {
               "id": "Different feature sets"
             }
           ]
         },
         {
           "id": "Methods",
           "children": [
             {
               "id": "Classifier selection"
             },
             {
               "id": "Classifier fusion"
             }
           ]
         },
         {
           "id": "Common",
           "children": [
             {
               "id": "Bagging"
             },
             {
               "id": "Boosting"
             },
             {
               "id": "AdaBoost"
             }
           ]
         }
       ]
     },
     {
       "id": "Regression",
       "children": [
         {
           "id": "Multiple linear regression"
         },
         {
           "id": "Partial least squares"
         },
         {
           "id": "Multi-layer feedforward neural network"
         },
         {
           "id": "General regression neural network"
         },
         {
           "id": "Support vector regression"
         }
       ]
     }
   ]
 };

const graph = new Graph({
  container: 'container',
  autoFit: 'view',
  data: treeToGraphData(data),
  node: {
    style: {
      labelText: (d) => d.id,
      labelBackground: true,
      labelPlacement: function (d) {
        const side = getNodeSide(this, d);
        return side === 'center' ? 'right' : side;
      },
      ports: [{ placement: 'right' }, { placement: 'left' }],
    },
    animation: {
      enter: false,
    },
  },
  edge: {
    type: 'cubic-horizontal',
    animation: {
      enter: false,
    },
  },
  layout: {
    type: 'mindmap',
    direction: 'H',
    preLayout: false,
    getHeight: () => 32,
    getWidth: () => 32,
    getVGap: () => 4,
    getHGap: () => 64,
    getSide: (d) => {
      if (d.id === 'Classification') {
        return 'left';
      }
      return 'right';
    },
  },
  behaviors: ['collapse-expand', 'drag-canvas', 'zoom-canvas'],
});
graph.render();

