  // 添加一些交叉边
  { id: 'e9', source: 'node4', target: 'node6' },
  { id: 'e10', source: 'node5', target: 'node7' },
];

// 转换节点数据格式
const nodes = rawNodes.map((node) => ({
  id: node.id,
  data: {
    size: node.size,
    isLeaf: node.isLeaf || false,
  },
}));

