  container: container,
  width: 800,
  height: 600,
  autoFit: 'view',

  data: {
    nodes,
    edges,
  },

  node: {
    type: 'circle',
    style: {
      size: (d) => d.data.size,
      fill: (d) => (d.data.isLeaf ? '#52C41A' : '#1783FF'),
      stroke: '#fff',
      lineWidth: 2,
      labelText: (d) => d.id,
      labelPlacement: 'bottom',
      labelFill: '#333',
      labelFontSize: 12,
    },
