    type: 'line',
    style: {
      stroke: '#aaa',
      lineWidth: 1.5,
      endArrow: true,
    },
  },

  layout: {
    type: 'd3-force',
    alpha: 0.5,
    alphaDecay: 0.02,
    alphaMin: 0.001,
    velocityDecay: 0.4,
    forces: [
      // 连接力 - 根据节点类型动态调整距离
      {
        type: 'link',
        id: 'link',
        distance: (edge, index, edges) => {
