        strength: (edge, index, edges) => {
          const sourceNode = nodes.find((n) => n.id === edge.source);
          const targetNode = nodes.find((n) => n.id === edge.target);
          // 叶节点连接更弱，允许更灵活的位置
          if (sourceNode?.data.isLeaf || targetNode?.data.isLeaf) {
            return 0.3;
          }
          return 0.5;
        },
      },
      // 多体力（电荷力）- 叶节点具有更强的排斥力
      {
        type: 'manyBody',
        id: 'manyBody',
        strength: (node, index, nodes) => {
          // 叶节点具有更强的排斥力，使它们分散得更开
          if (node.data.isLeaf) {
            return -300;
          }
          // 中心节点排斥力较弱
          if (node.id === 'node0') {
            return -100;
          }
          return -200;
        },
        theta: 0.9,
        distanceMin: 1,
        distanceMax: 500,
      },
      // 中心力 - 将图保持在画布中心
      {
        type: 'center',
        id: 'center',
        x: 400,
        y: 300,
        strength: 0.05,
      },
      // 碰撞力 - 防止节点重叠，根据节点大小调整
      {
        type: 'collision',
        id: 'collision',
        radius: (node) => node.data.size / 2 + 5,
        strength: 0.7,
        iterations: 1,
      },
    ],
    tick: () => {
      graph.draw();
    },
  },

  behaviors: ['drag-canvas', 'zoom-canvas', 'drag-element-force'],

  animation: true,
});

graph.render();

