  { id: 'highlight', data: { label: 'Highlight', type: 'state' }, states: ['highlight'] },
  { id: 'inactive', data: { label: 'Inactive', type: 'state' }, states: ['inactive'] },
  { id: 'disabled', data: { label: 'Disabled', type: 'state' }, states: ['disabled'] },
];

// 创建边连接所有节点形成网格关系
const edges = [
  { source: 'default', target: 'halo' },
  { source: 'halo', target: 'badges' },
  { source: 'badges', target: 'ports' },
  { source: 'ports', target: 'active' },
  { source: 'active', target: 'selected' },
  { source: 'selected', target: 'highlight' },
  { source: 'highlight', target: 'inactive' },
  { source: 'inactive', target: 'disabled' },
  { source: 'disabled', target: 'default' },
];

