import { Graph } from '@antv/g6';

// 参考数据
const rawData = [
  { id: '0', label: '0', value: 10, cluster: 'a', description: 'this is node 0, \nand the value of it is 10' },
  { id: '1', label: '1', value: 20, cluster: 'b', description: 'this is node 1, \nand the value of it is 20' },
  { id: '2', label: '2', value: 5, cluster: 'a', description: 'this is node 2, \nand the value of it is 5' },
  { id: '3', label: '3', value: 10, cluster: 'a', description: 'this is node 3, \nand the value of it is 10' },
  { id: '4', label: '4', value: 12, cluster: 'c', subCluster: 'sb', description: 'this is node 4, \nand the value of it is 12' },
  { id: '5', label: '5', value: 18, cluster: 'c', subCluster: 'sa', description: 'this is node 5, \nand the value of it is 18' },
  { id: '6', label: '6', value: 3, cluster: 'c', subCluster: 'sa', description: 'this is node 6, \nand the value of it is 3' },
  { id: '7', label: '7', value: 7, cluster: 'b', subCluster: 'sa', description: 'this is node 7, \nand the value of it is 7' },
  { id: '8', label: '8', value: 21, cluster: 'd', subCluster: 'sb', description: 'this is node 8, \nand the value of it is 21' },
  { id: '9', label: '9', value: 9, cluster: 'd', subCluster: 'sb', description: 'this is node 9, \nand the value of it is 9' },
];

// 颜色映射
const colorMap = {
  a: '#1783FF',
  b: '#F08F56',
  c: '#61DDAA',
  d: '#F6BD16',
};

// 生成随机边（确保没有重复边）
const edges = [];
const edgeSet = new Set();
for (let i = 0; i < rawData.length; i++) {
  for (let j = i + 1; j < rawData.length; j++) {
    if (Math.random() > 0.6) {
      const source = rawData[i].id;
      const target = rawData[j].id;
      const key = `${source}-${target}`;
      if (!edgeSet.has(key)) {
        edgeSet.add(key);
        edges.push({ source, target });
      }
    }
 else {
      break;
    }
  }
}

// 构建节点数据，添加随机初始尺寸
const nodes = rawData.map((item) => {
  const originalSize = 20 + Math.random() * 30; // 随机初始尺寸 20-50
  return {
    id: item.id,
    data: {
      ...item,
      originalSize,
      isLarge: false,
    },
  };
});

const graph = new Graph({
  container: container,
  width: 800,
  height: 600,
  autoFit: 'view',
  data: {
    nodes,
    edges,
  },
  node: {
    type: 'circle',
    style: {
      size: (d) => (d.data.isLarge ? 60 : d.data.originalSize),
      fill: (d) => colorMap[d.data.cluster] || '#999',
      stroke: '#fff',
      lineWidth: 2,
      labelText: (d) => d.data.label,
      labelPlacement: 'bottom',
      labelFill: '#333',
      labelFontSize: 12,
    },
  },
  edge: {
    type: 'line',
    style: {
      stroke: '#ccc',
      lineWidth: 1,
    },
  },
  layout: {
    type: 'force',
    preventOverlap: true,
    linkDistance: 100,
    nodeStrength: -30,
    edgeStrength: 0.1,
  },
  behaviors: ['drag-canvas', 'zoom-canvas', 'drag-element'],
  animation: true,
});

// 点击节点切换大小并重新布局
graph.on('node:click', (evt) => {
  const nodeId = evt.target.id;
  const nodeData = graph.getNodeData(nodeId);

  if (nodeData) {
    const newIsLarge = !nodeData.data.isLarge;

    // 更新节点数据
    graph.updateNodeData([
      {
        id: nodeId,
        data: {
          ...nodeData.data,
          isLarge: newIsLarge,
        },
      },
    ]);

    // 重新渲染和布局
    graph.draw();
    graph.layout();
  }
});

graph.render();

